const body = $input.first().json.body ?? $input.first().json;
const from    = String(body.from ?? '').replace(/^\+/, '');
const message = String(body.message ?? '').trim();
const orgId   = String(body.org_id ?? '');
if (!from || !message || !orgId) throw new Error('Missing fields: ' + JSON.stringify({ from, message, orgId }));
const isAudio = String(body.is_audio ?? 'false');
return [{ json: { from, message, org_id: orgId, is_audio: isAudio } }];

﻿const ctx      = $('Build Context').item.json;
const userId   = ctx.user_id;
const orgId    = ctx.org_id;
const userRole = ctx.user_role ?? 'employee';
const isAdmin  = userRole !== 'employee';
const isAudio  = String(ctx.is_audio ?? 'false') === 'true';

// ─── Interactive button/list reply pre-processing ────────────────────────────
// WhatsApp sends button/list reply as the item's ID string.
// Some IDs we handle immediately (return list/buttons without calling LLM).
// Others we translate to human-readable text so the LLM understands context.

const FIELD_LIST = [{ title: 'What to change?', rows: [
  { id: 'field_title',    title: 'Title',    description: 'Change the task name' },
  { id: 'field_assignee', title: 'Assignee', description: 'Assign to someone else' },
  { id: 'field_deadline', title: 'Deadline', description: 'Change the due date' },
  { id: 'field_priority', title: 'Priority', description: 'Low / Medium / High / Urgent' },
  { id: 'field_status',   title: 'Status',   description: 'To Do / In Progress / Done / Cancelled' }
]}];

const PRIORITY_LIST = [{ title: 'Priority', rows: [
  { id: 'priority_low',    title: '🟢 Low' },
  { id: 'priority_medium', title: '🟡 Medium' },
  { id: 'priority_high',   title: '🟠 High' },
  { id: 'priority_urgent', title: '🔴 Urgent' }
]}];

const STATUS_LIST = [{ title: 'Status', rows: [
  { id: 'status_todo',        title: '📋 To Do' },
  { id: 'status_in_progress', title: '⏳ In Progress' },
  { id: 'status_done',        title: '✅ Done' },
  { id: 'status_cancelled',   title: '❌ Cancelled' }
]}];

// IDs that short-circuit — return interactive UI immediately, no LLM call
const SHORTCUT_MAP = {
  'no_cancel':      { output: 'What would you like to change?', listItems: FIELD_LIST, listButtonLabel: 'Choose field' },
  'field_priority': { output: 'Choose the priority:', listItems: PRIORITY_LIST, listButtonLabel: 'Choose priority' },
  'field_status':   { output: 'Choose the status:', listItems: STATUS_LIST, listButtonLabel: 'Choose status' },
  'field_title':    { output: '✏️ What should the new title be? Please type it.' },
  'field_assignee': { output: '👤 Who should this be assigned to? Please type their name.' },
  'field_deadline': { output: '📅 What should the new deadline be? (e.g. "tomorrow", "25 Jun 2026")' },
};

// IDs that need LLM — translate to human text first
const BUTTON_ID_MAP = {
  'yes_confirm':        'Yes, please proceed with the action.',
  'priority_low':       'Set priority to: low',
  'priority_medium':    'Set priority to: medium',
  'priority_high':      'Set priority to: high',
  'priority_urgent':    'Set priority to: urgent',
  'status_todo':        'Set status to: todo',
  'status_in_progress': 'Set status to: in_progress',
  'status_done':        'Set status to: done',
  'status_cancelled':   'Set status to: cancelled',
};

const rawMsg = ctx.message;

if (SHORTCUT_MAP[rawMsg] !== undefined) {
  return [{ json: SHORTCUT_MAP[rawMsg] }];
}

const isButtonReply    = BUTTON_ID_MAP[rawMsg] !== undefined;
const effectiveMessage = isButtonReply ? BUTTON_ID_MAP[rawMsg] : rawMsg;

const isGreeting = String(ctx.is_greeting) === 'true';
const groqKey  = $('Secrets').item.json.groq_key;
const groqKey2 = $('Secrets').item.json.groq_key_2 || '';
const groqKey3 = $('Secrets').item.json.groq_key_3 || '';
const orKey    = $('Secrets').item.json.openrouter_key || '';
const sbUrl    = $('Secrets').item.json.supabase_url;
const sbKey    = $('Secrets').item.json.supabase_key;
const sbHeaders = { apikey: sbKey, Authorization: 'Bearer ' + sbKey };

const tools = [
  {
    type: 'function',
    function: {
      name: 'list_tasks',
      description: isAdmin
        ? 'List active tasks. Pass assignee_name to filter by a specific team member, or omit for all org tasks.'
        : 'List YOUR OWN active tasks. Employees cannot see other people\'s tasks.',
      parameters: {
        type: 'object',
        properties: isAdmin ? {
          assignee_name: { type: 'string', description: 'Filter by team member name (optional, admin/manager only)' }
        } : {}
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'create_task',
      description: 'Create a BRAND NEW task that does not exist yet. NEVER use this to reassign, update, or modify an existing task — use update_task for that. Before calling, ask for: title (required), assignee_name (ask who to assign to — if not specified, leave blank and it defaults to the current user), deadline and priority (both optional).',
      parameters: {
        type: 'object',
        properties: {
          title:         { type: 'string' },
          deadline:      { type: 'string', description: 'YYYY-MM-DD only (no time component). Pass null if user did NOT explicitly provide a date or deadline. NEVER invent or assume a deadline.' },
          priority:      { type: 'string', enum: ['low','medium','high','urgent'] },
          assignee_name: { type: 'string', description: 'Name of team member to assign to (admin can assign to others)' }
        },
        required: ['title']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'update_task',
      description: 'Update or reassign an EXISTING task. Use this for status changes, deadline changes, priority changes, AND reassigning the task to someone else (via assignee_name). Identify the task with task_id (UUID) OR task_title (the exact title). If the task was just created in this conversation, use task_title with the title that was confirmed.',
      parameters: {
        type: 'object',
        properties: {
          task_id:       { type: 'string', description: 'UUID of the task (preferred, from list_tasks)' },
          task_title:    { type: 'string', description: 'Exact title of the task (use if task_id unknown)' },
          status:        { type: 'string', enum: ['todo','in_progress','done','cancelled'] },
          title:         { type: 'string', description: 'New title for the task' },
          deadline:      { type: 'string', description: 'YYYY-MM-DD only (preferred) or YYYY-MM-DDTHH:MM:SS if user gave an explicit time. If user gives ONLY a date, pass YYYY-MM-DD — do NOT add a time from memory, history, or the task current deadline. If user asks to update deadline/due time but did NOT say what the new value is in the current message, do NOT call this tool — ask the user for the new deadline first.' },
          priority:      { type: 'string', enum: ['low','medium','high','urgent'] },
          assignee_name: { type: 'string', description: 'Name of team member to reassign the task to' }
        }
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'check_in',
      description: 'Record attendance check-in for the current user.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'check_out',
      description: 'Record attendance check-out for the current user.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'check_leave_balance',
      description: 'Get remaining leave balance for the current user.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'apply_leave',
      description: 'Submit a leave request. Ask user for leave type, dates, and reason first.',
      parameters: {
        type: 'object',
        properties: {
          leave_type_id: { type: 'string', description: 'UUID of leave type (get from check_leave_balance)' },
          start_date:    { type: 'string', description: 'YYYY-MM-DD' },
          end_date:      { type: 'string', description: 'YYYY-MM-DD' },
          reason:        { type: 'string' }
        },
        required: ['leave_type_id','start_date','end_date']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'list_leaves',
      description: 'List recent leave requests for the current user.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'daily_briefing',
      description: 'Get today briefing: pending tasks, attendance status, leave balance.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'my_attendance',
      description: 'Fetch attendance log for the current user this month.',
      parameters: { type: 'object', properties: {} }
    }
  },
  ...(isAdmin ? [
    {
      type: 'function',
      function: {
        name: 'team_attendance',
        description: 'Fetch today attendance for the whole team. Admin/manager only.',
        parameters: { type: 'object', properties: {} }
      }
    },
    {
      type: 'function',
      function: {
        name: 'list_pending_leaves',
        description: 'List all pending leave requests awaiting admin/manager review.',
        parameters: { type: 'object', properties: {} }
      }
    },
    {
      type: 'function',
      function: {
        name: 'approve_leave_request',
        description: 'Approve a pending leave request. Always confirm with the user before calling.',
        parameters: {
          type: 'object',
          properties: {
            leave_id: { type: 'string', description: 'UUID of the leave request (from list_pending_leaves)' }
          },
          required: ['leave_id']
        }
      }
    },
    {
      type: 'function',
      function: {
        name: 'reject_leave_request',
        description: 'Reject a pending leave request with a reason.',
        parameters: {
          type: 'object',
          properties: {
            leave_id:         { type: 'string', description: 'UUID of the leave request' },
            rejection_reason: { type: 'string', description: 'Reason for rejection' }
          },
          required: ['leave_id','rejection_reason']
        }
      }
    }
  ] : []),
  {
    type: 'function',
    function: {
      name: 'delete_task',
      description: 'Permanently delete a task. Use ONLY when user explicitly asks to delete/remove a task. Always confirm with the user before calling.',
      parameters: {
        type: 'object',
        properties: {
          task_id:    { type: 'string', description: 'UUID of the task (preferred)' },
          task_title: { type: 'string', description: 'Exact title of the task (use if task_id unknown)' }
        }
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'help',
      description: 'Get list of supported commands.',
      parameters: { type: 'object', properties: {} }
    }
  }
];

async function runTool(name, args) {
  const today = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
  const now   = new Date().toISOString();

  if (name === 'list_tasks') {
    if (!isAdmin && args.assignee_name) {
      return { denied: true, message: "🚫 You don't have permission to view other people's tasks. Type *my tasks* to see your own." };
    }
    let userFilter = isAdmin ? '' : '&assignee_id=eq.' + userId;
    if (isAdmin && args.assignee_name) {
      const users = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/users?organization_id=eq.' + orgId +
             '&full_name=ilike.' + encodeURIComponent('%' + args.assignee_name.trim() + '%') +
             '&select=id,full_name&limit=5',
        headers: sbHeaders
      });
      if (Array.isArray(users) && users.length > 0) userFilter = '&assignee_id=eq.' + users[0].id;
      else return { error: 'User "' + args.assignee_name + '" not found in this organisation.' };
    }
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/tasks?status=not.in.(done,cancelled)&deleted_at=is.null&organization_id=eq.' + orgId +
           userFilter + '&select=id,title,deadline,due_time,priority,status,assignee:users!tasks_assignee_id_fkey(full_name)' +
           '&order=deadline.asc.nullslast&limit=30',
      headers: sbHeaders
    });
  }

  if (name === 'create_task') {
    let assigneeId        = userId;
    let assigneeFirstName = ctx.user_name;
    let assigneeWa        = null;
    if (args.assignee_name && args.assignee_name.trim()) {
      const users = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/users?organization_id=eq.' + orgId +
             '&full_name=ilike.' + encodeURIComponent(args.assignee_name.trim() + '%') +
             '&select=id,full_name,wa_number&limit=5',
        headers: sbHeaders
      });
      if (Array.isArray(users) && users.length > 0) {
        assigneeId        = users[0].id;
        assigneeFirstName = users[0].full_name.split(' ')[0];
        assigneeWa        = users[0].wa_number;
      } else {
        return { error: 'User "' + args.assignee_name + '" not found in this organisation.' };
      }
    }
    const created = await helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/tasks',
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify({
        title: args.title,
        deadline: args.deadline ? args.deadline.split('T')[0] : null,
        priority: args.priority ?? 'medium',
        organization_id: orgId,
        assignee_id: assigneeId,
        created_by: userId,
        status: 'todo',
        source: 'whatsapp'
      })
    });
    // Instantly notify assignee if task was assigned to someone else
    if (assigneeId !== userId && assigneeWa) {
      const pEmoji   = { urgent: '🔴', high: '🟠', medium: '🟡', low: '🟢' }[args.priority ?? 'medium'] ?? '⚪';
      const dlLabel  = args.deadline
        ? new Date(args.deadline).toLocaleDateString('en-IN', { timeZone: 'Asia/Kolkata', day: 'numeric', month: 'short', year: 'numeric' })
        : null;
      const notifMsg =
        '📋 *Hi ' + assigneeFirstName + ', you have a new task!*\n\n' +
        '*' + args.title + '*\n\n' +
        pEmoji + ' Priority: *' + (args.priority ?? 'medium') + '*\n' +
        (dlLabel ? '🗓 Deadline: *' + dlLabel + '*\n' : '') +
        '👤 Assigned by: *' + ctx.user_name + '*\n\n' +
        'Reply *my tasks* to view all your pending tasks.';
      try {
        await helpers.httpRequest({
          method: 'POST',
          url: 'https://whatsapp-hrbot.vercel.app/api/wa/send',
          headers: { Authorization: 'Bearer 0yxnvS8z3lpb2AG4Ljjx8TynSI0edL7NKNGJnKKnyhvO3OFK', 'Content-Type': 'application/json' },
          body: JSON.stringify({ to: assigneeWa, text: notifMsg, organization_id: orgId })
        });
      } catch(e) { /* don't let notification failure block task creation */ }
    }
    return created;
  }

  if (name === 'update_task') {
    let taskId = args.task_id;
    if (!taskId && args.task_title) {
      const found = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/tasks?organization_id=eq.' + orgId +
             '&title=ilike.' + encodeURIComponent(args.task_title.trim()) +
             '&deleted_at=is.null&select=id&limit=1',
        headers: sbHeaders
      });
      if (Array.isArray(found) && found.length > 0) taskId = found[0].id;
      else return { error: 'Task "' + args.task_title + '" not found.' };
    }
    if (!taskId) return { error: 'Provide task_id or task_title.' };

    const patch = {};
    if (args.status)   patch.status   = args.status;
    if (args.title)    patch.title    = args.title;
    if (args.priority) patch.priority = args.priority;
    if (args.deadline) {
      // If date-only (YYYY-MM-DD), store just the date and clear any stored time
      if (/^\d{4}-\d{2}-\d{2}$/.test(args.deadline)) {
        patch.deadline = args.deadline;
        patch.due_time = null;
      } else if (/^\d{4}-\d{2}-\d{2}T/.test(args.deadline)) {
        patch.deadline = args.deadline.split('T')[0];
        const tp = args.deadline.split('T')[1];
        patch.due_time = tp ? tp.slice(0, 8) : null;
      } else {
        patch.deadline = args.deadline;
      }
    }
    if (args.assignee_name) {
      const users = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/users?organization_id=eq.' + orgId +
             '&full_name=ilike.' + encodeURIComponent(args.assignee_name.trim() + '%') +
             '&select=id,full_name&limit=5',
        headers: sbHeaders
      });
      if (Array.isArray(users) && users.length > 0) patch.assignee_id = users[0].id;
      else return { error: 'User "' + args.assignee_name + '" not found in this organisation.' };
    }
    if (Object.keys(patch).length === 0) return { error: 'Nothing to update.' };

    return helpers.httpRequest({
      method: 'PATCH',
      url: sbUrl + '/rest/v1/tasks?id=eq.' + taskId + '&organization_id=eq.' + orgId,
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify(patch)
    });
  }


  if (name === 'delete_task') {
    let taskId = args.task_id;
    if (!taskId && args.task_title) {
      const found = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/tasks?organization_id=eq.' + orgId +
             '&title=ilike.' + encodeURIComponent(args.task_title.trim()) +
             '&deleted_at=is.null&select=id&limit=1',
        headers: sbHeaders
      });
      if (Array.isArray(found) && found.length > 0) taskId = found[0].id;
      else return { error: 'Task "' + args.task_title + '" not found.' };
    }
    if (!taskId) return { error: 'Provide task_id or task_title to delete.' };
    await helpers.httpRequest({
      method: 'PATCH',
      url: sbUrl + '/rest/v1/tasks?id=eq.' + taskId + '&organization_id=eq.' + orgId,
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify({ deleted_at: new Date().toISOString() })
    });
    return { success: true, message: 'Task deleted successfully.' };
  }

  if (name === 'check_in') {
    const todayIST = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
    const nowISO   = new Date().toISOString();
    const existing = await helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/attendance_records?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId + '&date=eq.' + todayIST +
           '&select=id,check_in_time,check_out_time',
      headers: sbHeaders
    });
    if (Array.isArray(existing) && existing.length > 0) {
      const cinFmt = new Date(existing[0].check_in_time).toLocaleTimeString('en-IN',
        { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' });
      return { already_checked_in: true, check_in_time: cinFmt,
               message: 'You already checked in today at ' + cinFmt + '.' };
    }
    const inserted = await helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/attendance_records',
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify({
        organization_id: orgId,
        employee_id:     userId,
        date:            todayIST,
        check_in_time:   nowISO,
        status:          'present',
        source:          'whatsapp'
      })
    });
    const cinFmt = new Date(nowISO).toLocaleTimeString('en-IN',
      { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' });
    const dateFmt = new Date(nowISO).toLocaleDateString('en-IN', { timeZone: 'Asia/Kolkata', day: 'numeric', month: 'short', year: 'numeric' });
    return { success: true, check_in_time: cinFmt, date: dateFmt,
             message: 'Checked in at ' + cinFmt };
  }

  if (name === 'check_out') {
    const todayIST = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
    const nowISO   = new Date().toISOString();
    const records  = await helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/attendance_records?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId + '&date=eq.' + todayIST +
           '&select=id,check_in_time,check_out_time',
      headers: sbHeaders
    });
    if (!Array.isArray(records) || records.length === 0) {
      return { error: "You haven't checked in today yet. Reply *checkin* to check in first." };
    }
    const record = records[0];
    if (record.check_out_time) {
      const coutFmt = new Date(record.check_out_time).toLocaleTimeString('en-IN',
        { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' });
      return { already_checked_out: true, check_out_time: coutFmt,
               message: 'You already checked out today at ' + coutFmt + '.' };
    }
    const cinFmt = new Date(record.check_in_time).toLocaleTimeString('en-IN',
      { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' });
    await helpers.httpRequest({
      method: 'PATCH',
      url: sbUrl + '/rest/v1/attendance_records?id=eq.' + record.id + '&organization_id=eq.' + orgId,
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify({ check_out_time: nowISO })
    });
    // Compute duration
    const minsDiff = Math.round((new Date(nowISO) - new Date(record.check_in_time)) / 60000);
    const hrs  = Math.floor(minsDiff / 60);
    const mins = minsDiff % 60;
    const duration = hrs > 0 ? hrs + 'h ' + mins + 'm' : mins + 'm';
    const coutFmt2 = new Date(nowISO).toLocaleTimeString('en-IN',
      { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' });
    return {
      success:        true,
      check_in_time:  cinFmt,
      check_out_time: coutFmt2,
      duration,
      message: 'Checked out at ' + coutFmt2 + '. You worked for ' + duration + ' today (checked in at ' + cinFmt + ').'
    };
  }

  if (name === 'check_leave_balance') {
    const balanceRows = await helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/leave_balances?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId +
           '&select=id,remaining_days,entitled_days,used_days,leave_type_id,leave_type:leave_types(id,name)',
      headers: sbHeaders
    });
    if (Array.isArray(balanceRows) && balanceRows.length > 0) return balanceRows;
    // No balance rows: fall back to org leave types (user can still apply, balance tracked separately)
    const leaveTypes = await helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/leave_types?organization_id=eq.' + orgId + '&select=id,name,default_days',
      headers: sbHeaders
    });
    if (!Array.isArray(leaveTypes) || leaveTypes.length === 0) {
      return { message: 'No leave types configured for your organisation. Contact HR.' };
    }
    return leaveTypes.map(function(lt) {
      return { leave_type_id: lt.id, remaining_days: lt.default_days, entitled_days: lt.default_days, used_days: 0, leave_type: { id: lt.id, name: lt.name } };
    });
  }

  if (name === 'apply_leave') {
    const startD = new Date(args.start_date);
    const endD   = new Date(args.end_date);
    if (endD < startD) return { error: 'End date cannot be before start date.' };
    const durDays = Math.round((endD - startD) / 86400000) + 1;
    return helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/leave_requests',
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify({
        organization_id: orgId,
        employee_id:     userId,
        leave_type_id:   args.leave_type_id,
        start_date:      args.start_date,
        end_date:        args.end_date,
        duration_days:   durDays,
        reason:          args.reason || '',
        status:          'pending'
      })
    });
  }

