async function groqCall(msgs, toolChoice) {
  const keys = [groqKey, groqKey2, groqKey3].filter(Boolean);
  let lastErr;
  for (const k of keys) {
    try {
      return await helpers.httpRequest({
        method: 'POST',
        url: 'https://api.groq.com/openai/v1/chat/completions',
        headers: { Authorization: 'Bearer ' + k, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'llama-3.3-70b-versatile',
          messages: msgs, tools, tool_choice: toolChoice || 'auto', max_tokens: 1024, temperature: 0.3
        })
      });
    } catch(e) {
      const code = String(e.message);
      if (code.includes('429') || code.includes('400')) { lastErr = e; continue; }
      throw e;
    }
  }
  throw lastErr;
}

async function llmCall(msgs, toolChoice) {
  try {
    return await groqCall(msgs, toolChoice);
  } catch(e) {
    if (orKey) {
      return await helpers.httpRequest({
        method: 'POST',
        url: 'https://openrouter.ai/api/v1/chat/completions',
        headers: { Authorization: 'Bearer ' + orKey, 'Content-Type': 'application/json', 'HTTP-Referer': 'https://whatsapp-hrbot.vercel.app' },
        body: JSON.stringify({ model: 'meta-llama/llama-3.3-70b-instruct', messages: msgs, tools, tool_choice: toolChoice || 'auto', max_tokens: 1024, temperature: 0.3 })
      });
    }
    throw e;
  }
}

