let output = (choice.message.content || '').trim();

  // Strip code-block fences and try to recover a leaked tool call
  const fenceMatch = output.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fenceMatch) {
    const inner = fenceMatch[1].trim();
    if (inner.startsWith('{')) {
      try {
        const tc = JSON.parse(inner);
        const toolName = tc.name || (tc.function && tc.function.name);
        const rawArgs  = tc.parameters || tc.arguments || {};
        const toolArgs = typeof rawArgs === 'string' ? JSON.parse(rawArgs) : rawArgs;
        if (toolName && tools.some(function(t){ return t.function.name === toolName; }) && iters < 5) {
          const toolRes = await runTool(toolName, toolArgs);
          const callId  = 'recovered_' + Date.now();
          messages.push({ role: 'assistant', content: null,
            tool_calls: [{ id: callId, type: 'function',
              function: { name: toolName, arguments: JSON.stringify(toolArgs) } }] });
          messages.push({ role: 'tool', tool_call_id: callId, content: JSON.stringify(toolRes) });
          const finalResp = await llmCall(messages, 'none');
          output = (finalResp.choices[0].message.content || '').trim();
        } else {
          output = '';
        }
      } catch(e2) { output = ''; }
    } else {
      output = inner;
    }
  }

  // Also recover bare JSON tool call (no code fence)
  if (!fenceMatch && /^\s*\{/.test(output)) {
    try {
      const tc = JSON.parse(output);
      const toolName = tc.name || (tc.function && tc.function.name);
      const rawArgs  = tc.parameters || tc.arguments || {};
      const toolArgs = typeof rawArgs === 'string' ? JSON.parse(rawArgs) : rawArgs;
      if (toolName && tools.some(function(t){ return t.function.name === toolName; }) && iters < 5) {
        const toolRes = await runTool(toolName, toolArgs);
        const callId  = 'recovered_' + Date.now();
