          deadline:      { type: 'string', description: 'YYYY-MM-DD only (preferred) or YYYY-MM-DDTHH:MM:SS if user gave an explicit time. If user gives ONLY a date, pass YYYY-MM-DD — do NOT add a time from memory, history, or the task current deadline. If user asks to update deadline/due time but did NOT say what the new value is in the current message, do NOT call this tool — ask the user for the new deadline first.' },
          priority:      { type: 'string', enum: ['low','medium','high','urgent'] },
          assignee_name: { type: 'string', description: 'Name of team member to reassign the task to' }
        }
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'check_in',
      description: 'Record attendance check-in for the current user.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'check_out',
      description: 'Record attendance check-out for the current user.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'check_leave_balance',
      description: 'Get remaining leave balance for the current user.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'apply_leave',
      description: 'Submit a leave request. Ask user for leave type, dates, and reason first.',
      parameters: {
        type: 'object',
        properties: {
          leave_type_id: { type: 'string', description: 'UUID of leave type (get from check_leave_balance)' },
          start_date:    { type: 'string', description: 'YYYY-MM-DD' },
          end_date:      { type: 'string', description: 'YYYY-MM-DD' },
          reason:        { type: 'string' }
        },
        required: ['leave_type_id','start_date','end_date']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'list_leaves',
      description: 'List recent leave requests for the current user.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'daily_briefing',
      description: 'Get today briefing: pending tasks, attendance status, leave balance.',
      parameters: { type: 'object', properties: {} }
    }
  },
  {
    type: 'function',
    function: {
      name: 'my_attendance',
      description: 'Fetch attendance log for the current user this month.',
      parameters: { type: 'object', properties: {} }
    }
  },
  ...(isAdmin ? [
    {
      type: 'function',
      function: {
        name: 'team_attendance',
        description: 'Fetch today attendance for the whole team. Admin/manager only.',
        parameters: { type: 'object', properties: {} }
      }
    },
    {
      type: 'function',
      function: {
        name: 'list_pending_leaves',
        description: 'List all pending leave requests awaiting admin/manager review.',
        parameters: { type: 'object', properties: {} }
      }
    },
    {
      type: 'function',
      function: {
        name: 'approve_leave_request',
        description: 'Approve a pending leave request. Always confirm with the user before calling.',
        parameters: {
          type: 'object',
          properties: {
            leave_id: { type: 'string', description: 'UUID of the leave request (from list_pending_leaves)' }
          },
          required: ['leave_id']
        }
      }
    },
    {
      type: 'function',
      function: {
        name: 'reject_leave_request',
        description: 'Reject a pending leave request with a reason.',
        parameters: {
          type: 'object',
          properties: {
            leave_id:         { type: 'string', description: 'UUID of the leave request' },
            rejection_reason: { type: 'string', description: 'Reason for rejection' }
          },
          required: ['leave_id','rejection_reason']
        }
      }
    }
  ] : []),
  {
    type: 'function',
    function: {
      name: 'delete_task',
      description: 'Permanently delete a task. Use ONLY when user explicitly asks to delete/remove a task. Always confirm with the user before calling.',
      parameters: {
        type: 'object',
        properties: {
          task_id:    { type: 'string', description: 'UUID of the task (preferred)' },
          task_title: { type: 'string', description: 'Exact title of the task (use if task_id unknown)' }
        }
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'help',
      description: 'Get list of supported commands.',
      parameters: { type: 'object', properties: {} }
    }
  }
];

async function runTool(name, args) {
  const today = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
  const now   = new Date().toISOString();

  if (name === 'list_tasks') {
    if (!isAdmin && args.assignee_name) {
      return { denied: true, message: "🚫 You don't have permission to view other people's tasks. Type *my tasks* to see your own." };
    }
    let userFilter = isAdmin ? '' : '&assignee_id=eq.' + userId;
    if (isAdmin && args.assignee_name) {
      const users = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/users?organization_id=eq.' + orgId +
             '&full_name=ilike.' + encodeURIComponent('%' + args.assignee_name.trim() + '%') +
             '&select=id,full_name&limit=5',
        headers: sbHeaders
      });
      if (Array.isArray(users) && users.length > 0) userFilter = '&assignee_id=eq.' + users[0].id;
      else return { error: 'User "' + args.assignee_name + '" not found in this organisation.' };
    }
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/tasks?status=not.in.(done,cancelled)&deleted_at=is.null&organization_id=eq.' + orgId +
           userFilter + '&select=id,title,deadline,due_time,priority,status,assignee:users!tasks_assignee_id_fkey(full_name)' +
           '&order=deadline.asc.nullslast&limit=30',
      headers: sbHeaders
    });
  }

  if (name === 'create_task') {
    let assigneeId        = userId;
    let assigneeFirstName = ctx.user_name;
    let assigneeWa        = null;
    if (args.assignee_name && args.assignee_name.trim()) {
      const users = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/users?organization_id=eq.' + orgId +
             '&full_name=ilike.' + encodeURIComponent(args.assignee_name.trim() + '%') +
             '&select=id,full_name,wa_number&limit=5',
        headers: sbHeaders
      });
      if (Array.isArray(users) && users.length > 0) {
        assigneeId        = users[0].id;
        assigneeFirstName = users[0].full_name.split(' ')[0];
        assigneeWa        = users[0].wa_number;
      } else {
        return { error: 'User "' + args.assignee_name + '" not found in this organisation.' };
      }
    }
    const created = await helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/tasks',
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify({
        title: args.title,
        deadline: args.deadline ? args.deadline.split('T')[0] : null,
        priority: args.priority ?? 'medium',
        organization_id: orgId,
        assignee_id: assigneeId,
        created_by: userId,
        status: 'todo',
        source: 'whatsapp'
      })
    });
    // Instantly notify assignee if task was assigned to someone else
    if (assigneeId !== userId && assigneeWa) {
      const pEmoji   = { urgent: '🔴', high: '🟠', medium: '🟡', low: '🟢' }[args.priority ?? 'medium'] ?? '⚪';
      const dlLabel  = args.deadline
        ? new Date(args.deadline).toLocaleDateString('en-IN', { timeZone: 'Asia/Kolkata', day: 'numeric', month: 'short', year: 'numeric' })
        : null;
      const notifMsg =
        '📋 *Hi ' + assigneeFirstName + ', you have a new task!*\n\n' +
        '*' + args.title + '*\n\n' +
        pEmoji + ' Priority: *' + (args.priority ?? 'medium') + '*\n' +
        (dlLabel ? '🗓 Deadline: *' + dlLabel + '*\n' : '') +
        '👤 Assigned by: *' + ctx.user_name + '*\n\n' +
        'Reply *my tasks* to view all your pending tasks.';
      try {
        await helpers.httpRequest({
          method: 'POST',
          url: 'https://whatsapp-hrbot.vercel.app/api/wa/send',
          headers: { Authorization: 'Bearer 0yxnvS8z3lpb2AG4Ljjx8TynSI0edL7NKNGJnKKnyhvO3OFK', 'Content-Type': 'application/json' },
          body: JSON.stringify({ to: assigneeWa, text: notifMsg, organization_id: orgId })
        });
      } catch(e) { /* don't let notification failure block task creation */ }
    }
    return created;
  }

  if (name === 'update_task') {
    let taskId = args.task_id;
    if (!taskId && args.task_title) {
      const found = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/tasks?organization_id=eq.' + orgId +
             '&title=ilike.' + encodeURIComponent(args.task_title.trim()) +
             '&deleted_at=is.null&select=id&limit=1',
        headers: sbHeaders
      });
      if (Array.isArray(found) && found.length > 0) taskId = found[0].id;
      else return { error: 'Task "' + args.task_title + '" not found.' };
    }
    if (!taskId) return { error: 'Provide task_id or task_title.' };

    const patch = {};
    if (args.status)   patch.status   = args.status;
    if (args.title)    patch.title    = args.title;
    if (args.priority) patch.priority = args.priority;
    if (args.deadline) {
      // If date-only (YYYY-MM-DD), store just the date and clear any stored time
      if (/^\d{4}-\d{2}-\d{2}$/.test(args.deadline)) {
        patch.deadline = args.deadline;
        patch.due_time = null;
      } else if (/^\d{4}-\d{2}-\d{2}T/.test(args.deadline)) {
        patch.deadline = args.deadline.split('T')[0];
        const tp = args.deadline.split('T')[1];
        patch.due_time = tp ? tp.slice(0, 8) : null;
      } else {
        patch.deadline = args.deadline;
      }
    }
    if (args.assignee_name) {
      const users = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/users?organization_id=eq.' + orgId +
             '&full_name=ilike.' + encodeURIComponent(args.assignee_name.trim() + '%') +
             '&select=id,full_name&limit=5',
        headers: sbHeaders
      });
      if (Array.isArray(users) && users.length > 0) patch.assignee_id = users[0].id;
      else return { error: 'User "' + args.assignee_name + '" not found in this organisation.' };
    }
    if (Object.keys(patch).length === 0) return { error: 'Nothing to update.' };

    return helpers.httpRequest({
      method: 'PATCH',
      url: sbUrl + '/rest/v1/tasks?id=eq.' + taskId + '&organization_id=eq.' + orgId,
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify(patch)
    });
  }


  if (name === 'delete_task') {
    let taskId = args.task_id;
    if (!taskId && args.task_title) {
      const found = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/tasks?organization_id=eq.' + orgId +
             '&title=ilike.' + encodeURIComponent(args.task_title.trim()) +
             '&deleted_at=is.null&select=id&limit=1',
        headers: sbHeaders
      });
      if (Array.isArray(found) && found.length > 0) taskId = found[0].id;
      else return { error: 'Task "' + args.task_title + '" not found.' };
    }
    if (!taskId) return { error: 'Provide task_id or task_title to delete.' };
    await helpers.httpRequest({
      method: 'PATCH',
      url: sbUrl + '/rest/v1/tasks?id=eq.' + taskId + '&organization_id=eq.' + orgId,
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify({ deleted_at: new Date().toISOString() })
    });
    return { success: true, message: 'Task deleted successfully.' };
  }

  if (name === 'check_in') {
    const todayIST = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
    const nowISO   = new Date().toISOString();
    const existing = await helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/attendance_records?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId + '&date=eq.' + todayIST +
           '&select=id,check_in_time,check_out_time',
      headers: sbHeaders
    });
    if (Array.isArray(existing) && existing.length > 0) {
      const cinFmt = new Date(existing[0].check_in_time).toLocaleTimeString('en-IN',
        { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' });
      return { already_checked_in: true, check_in_time: cinFmt,
               message: 'You already checked in today at ' + cinFmt + '.' };
    }
    const inserted = await helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/attendance_records',
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify({
        organization_id: orgId,
        employee_id:     userId,
        date:            todayIST,
        check_in_time:   nowISO,
        status:          'present',
        source:          'whatsapp'
      })
    });
    const cinFmt = new Date(nowISO).toLocaleTimeString('en-IN',
      { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' });
    const dateFmt = new Date(nowISO).toLocaleDateString('en-IN', { timeZone: 'Asia/Kolkata', day: 'numeric', month: 'short', year: 'numeric' });
    return { success: true, check_in_time: cinFmt, date: dateFmt,
             message: 'Checked in at ' + cinFmt };
  }

  if (name === 'check_out') {
    const todayIST = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
    const nowISO   = new Date().toISOString();
    const records  = await helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/attendance_records?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId + '&date=eq.' + todayIST +
           '&select=id,check_in_time,check_out_time',
      headers: sbHeaders
    });
    if (!Array.isArray(records) || records.length === 0) {
      return { error: "You haven't checked in today yet. Reply *checkin* to check in first." };
    }
    const record = records[0];
    if (record.check_out_time) {
      const coutFmt = new Date(record.check_out_time).toLocaleTimeString('en-IN',
        { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' });
      return { already_checked_out: true, check_out_time: coutFmt,
               message: 'You already checked out today at ' + coutFmt + '.' };
    }
    const cinFmt = new Date(record.check_in_time).toLocaleTimeString('en-IN',
      { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' });
    await helpers.httpRequest({
      method: 'PATCH',
      url: sbUrl + '/rest/v1/attendance_records?id=eq.' + record.id + '&organization_id=eq.' + orgId,
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify({ check_out_time: nowISO })
    });
    // Compute duration
    const minsDiff = Math.round((new Date(nowISO) - new Date(record.check_in_time)) / 60000);
    const hrs  = Math.floor(minsDiff / 60);
    const mins = minsDiff % 60;
    const duration = hrs > 0 ? hrs + 'h ' + mins + 'm' : mins + 'm';
    const coutFmt2 = new Date(nowISO).toLocaleTimeString('en-IN',
      { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' });
    return {
      success:        true,
      check_in_time:  cinFmt,
      check_out_time: coutFmt2,
      duration,
      message: 'Checked out at ' + coutFmt2 + '. You worked for ' + duration + ' today (checked in at ' + cinFmt + ').'
    };
  }

  if (name === 'check_leave_balance') {
    const balanceRows = await helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/leave_balances?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId +
           '&select=id,remaining_days,entitled_days,used_days,leave_type_id,leave_type:leave_types(id,name)',
      headers: sbHeaders
    });
    if (Array.isArray(balanceRows) && balanceRows.length > 0) return balanceRows;
    // No balance rows: fall back to org leave types (user can still apply, balance tracked separately)
    const leaveTypes = await helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/leave_types?organization_id=eq.' + orgId + '&select=id,name,default_days',
      headers: sbHeaders
    });
    if (!Array.isArray(leaveTypes) || leaveTypes.length === 0) {
      return { message: 'No leave types configured for your organisation. Contact HR.' };
    }
    return leaveTypes.map(function(lt) {
      return { leave_type_id: lt.id, remaining_days: lt.default_days, entitled_days: lt.default_days, used_days: 0, leave_type: { id: lt.id, name: lt.name } };
    });
  }

  if (name === 'apply_leave') {
    const startD = new Date(args.start_date);
    const endD   = new Date(args.end_date);
    if (endD < startD) return { error: 'End date cannot be before start date.' };
    const durDays = Math.round((endD - startD) / 86400000) + 1;
    return helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/leave_requests',
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify({
        organization_id: orgId,
        employee_id:     userId,
        leave_type_id:   args.leave_type_id,
        start_date:      args.start_date,
        end_date:        args.end_date,
        duration_days:   durDays,
        reason:          args.reason || '',
        status:          'pending'
      })
    });
  }

  if (name === 'list_leaves') {
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/leave_requests?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId +
           '&select=start_date,end_date,duration_days,status,reason,leave_type:leave_types(name)' +
           '&order=created_at.desc&limit=10',
      headers: sbHeaders
    });
  }

  if (name === 'daily_briefing') {
    const todayIST = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
    const [tasks, attendance, balance] = await Promise.all([
      helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/tasks?assignee_id=eq.' + userId + '&organization_id=eq.' + orgId +
             '&status=not.in.(done,cancelled)&deleted_at=is.null' +
             '&select=title,deadline,priority&order=deadline.asc.nullslast&limit=5',
        headers: sbHeaders
      }),
      helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/attendance_records?employee_id=eq.' + userId +
             '&organization_id=eq.' + orgId + '&date=eq.' + todayIST +
             '&select=check_in_time,check_out_time,status',
        headers: sbHeaders
      }),
      helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/leave_balances?employee_id=eq.' + userId +
             '&organization_id=eq.' + orgId +
             '&select=remaining_days,leave_type:leave_types(name)',
        headers: sbHeaders
      })
    ]);
    function toIST(iso) {
      if (!iso) return null;
      return new Date(iso).toLocaleTimeString('en-IN', { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' });
    }
    function fmtDate(d) {
      if (!d) return null;
      return new Date(d + 'T00:00:00').toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' });
    }
    const att = Array.isArray(attendance) && attendance.length > 0 ? attendance[0] : null;
    return {
      today: new Date().toLocaleDateString('en-IN', { timeZone: 'Asia/Kolkata', weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }),
      pending_tasks: Array.isArray(tasks) ? tasks.map(function(t) {
        return { title: t.title, deadline: fmtDate(t.deadline), priority: t.priority };
      }) : [],
      attendance_today: att ? {
        status: att.status || 'present',
        checked_in: att.check_in_time ? 'Yes, at ' + toIST(att.check_in_time) + ' IST' : 'Not yet',
        checked_out: att.check_out_time ? 'Yes, at ' + toIST(att.check_out_time) + ' IST' : 'Not yet'
      } : { status: 'absent', checked_in: 'Not yet', checked_out: 'Not yet' },
      leave_balance: Array.isArray(balance) ? balance.map(function(l) {
        return { leave_type: l.leave_type ? l.leave_type.name : 'Leave', remaining_days: l.remaining_days };
      }) : []
    };
  }

  if (name === 'my_attendance') {
    const monthStart = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0];
    const rows = await helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/attendance_records?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId +
           '&date=gte.' + monthStart +
           '&select=date,check_in_time,check_out_time,status&order=date.desc&limit=31',
      headers: sbHeaders
    });
    if (!Array.isArray(rows)) return rows;
    return rows.map(function(r) {
      const d = r.date ? new Date(r.date + 'T00:00:00').toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }) : null;
      const ci = r.check_in_time  ? new Date(r.check_in_time).toLocaleTimeString('en-IN',  { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' }) + ' IST' : null;
      const co = r.check_out_time ? new Date(r.check_out_time).toLocaleTimeString('en-IN', { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' }) + ' IST' : null;
      return { date: d, check_in_time: ci, check_out_time: co, status: r.status };
    });
  }

  if (name === 'team_attendance') {
    const rows = await helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/attendance_records?organization_id=eq.' + orgId +
           '&date=eq.' + today +
           '&select=status,check_in_time,check_out_time,employee:users(full_name,role)' +
           '&order=check_in_time.asc',
      headers: sbHeaders
    });
    if (!Array.isArray(rows)) return rows;
    return rows.map(function(r) {
      function toIST(iso) {
        if (!iso) return null;
        return new Date(iso).toLocaleTimeString('en-IN', {
          timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit'
        }) + ' IST';
      }
      return {
        name:          r.employee ? r.employee.full_name : 'Unknown',
        status:        r.status,
        check_in_time: toIST(r.check_in_time),
        check_out_time: toIST(r.check_out_time)
      };
    });
  }

  if (name === 'list_pending_leaves') {
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/leave_requests?status=eq.pending&organization_id=eq.' + orgId +
           '&select=id,employee:users!leave_requests_employee_id_fkey(full_name),' +
           'leave_type:leave_types(name),start_date,end_date,duration_days,reason' +
           '&order=created_at.asc',
      headers: sbHeaders
    });
  }

  if (name === 'approve_leave_request') {
    return helpers.httpRequest({
      method: 'PATCH',
      url: sbUrl + '/rest/v1/leave_requests?id=eq.' + args.leave_id + '&organization_id=eq.' + orgId,
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify({ status: 'approved', reviewed_by: userId, reviewed_at: now })
    });
  }

  if (name === 'reject_leave_request') {
    return helpers.httpRequest({
      method: 'PATCH',
      url: sbUrl + '/rest/v1/leave_requests?id=eq.' + args.leave_id + '&organization_id=eq.' + orgId,
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify({ status: 'rejected', reviewed_by: userId, reviewed_at: now, rejection_reason: args.rejection_reason })
    });
  }

  if (name === 'help') {
    const adminCmds = isAdmin ? [
      'team attendance', 'pending leaves', 'approve leave <id>', 'reject leave <id>'
    ] : [];
    return {
      commands: [
        'list my tasks','create a task','update task status',
        'check in','check out','my attendance',
        'leave balance','apply leave','list leaves','daily briefing',
        ...adminCmds
      ]
    };
  }

  return { error: 'Unknown tool: ' + name };
}

const history = JSON.parse(ctx.history || '[]');
const taskRules = '\n\n*Task rules:*\n- To REASSIGN or UPDATE an existing task → always use update_task (with task_title or task_id). NEVER call create_task for an existing task.\n- To create a BRAND NEW task → ask for title + assignee (who to assign to). Deadline and priority are optional. Once you have title and know the assignee (or confirmed it defaults to the current user), call create_task immediately. Do NOT show a JSON block or add an extra confirmation step.\n- If a previous message said a task was "not found", try update_task with task_title anyway before giving up.\n- Task list display: use *bullet points*, format dates as "24 Jun 2026" (never YYYY-MM-DD), show due time as "at 11:00 AM" if available\n- VAGUE UPDATE RULE: If user wants to update a task but does NOT specify what to change (no new title/deadline/priority/status/assignee mentioned), ask: "What would you like to update?" and show these as bullet options: Title, Assignee, Deadline, Priority, Status.\n- MISSING VALUE RULE: If the user specifies WHICH field to update but does NOT give the new value in the CURRENT message, ask for the new value BEFORE calling update_task. Examples that must ASK: "update the due time", "change the due time", "update due date", "change the priority of X", "update the title of X", "change the status". The new value MUST appear in the current user message — do NOT infer it from history, context, or the task's existing value. Do NOT guess, repeat the current value, or use the current time.';
const roleNote = isAdmin
  ? '\n\nYou have *admin/manager* access:\n- list_tasks (no args) = ALL org tasks | to see YOUR tasks: pass your own name as assignee_name | assignee_name: "John" = only John tasks\n- team_attendance shows today team status\n- list_pending_leaves shows leaves awaiting your review\n- approve_leave_request / reject_leave_request to act on them\n- create_task can assign to any team member'
  : '';

const messages = [
  { role: 'system', content: ctx.system_prompt + taskRules + roleNote },
  ...history,
  { role: 'user', content: effectiveMessage }
];

async function groqCall(msgs, toolChoice) {
  const keys = [groqKey, groqKey2, groqKey3].filter(Boolean);
  let lastErr;
  for (const k of keys) {
    try {
      return await helpers.httpRequest({
        method: 'POST',
        url: 'https://api.groq.com/openai/v1/chat/completions',
        headers: { Authorization: 'Bearer ' + k, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'llama-3.3-70b-versatile',
          messages: msgs, tools, tool_choice: toolChoice || 'auto', max_tokens: 1024, temperature: 0.3
        })
      });
    } catch(e) {
      const code = String(e.message);
      if (code.includes('429') || code.includes('400')) { lastErr = e; continue; }
      throw e;
    }
  }
  throw lastErr;
}

async function llmCall(msgs, toolChoice) {
  try {
    return await groqCall(msgs, toolChoice);
  } catch(e) {
    if (orKey) {
      return await helpers.httpRequest({
        method: 'POST',
        url: 'https://openrouter.ai/api/v1/chat/completions',
        headers: { Authorization: 'Bearer ' + orKey, 'Content-Type': 'application/json', 'HTTP-Referer': 'https://whatsapp-hrbot.vercel.app' },
        body: JSON.stringify({ model: 'meta-llama/llama-3.3-70b-instruct', messages: msgs, tools, tool_choice: toolChoice || 'auto', max_tokens: 1024, temperature: 0.3 })
      });
    }
    throw e;
  }
}

let resp   = await llmCall(messages, isGreeting ? 'none' : 'auto');
let choice = resp.choices[0];
let iters  = 0;

while (!isGreeting && choice.finish_reason === 'tool_calls' && iters < 5) {
  const toolCalls = choice.message.tool_calls || [];

  // ── Write-action interceptor: force confirmation for audio/button-reply ──────
  // Runs BEFORE any tool executes. The LLM decides WHAT to do; we decide WHEN.
  const WRITE_TOOLS = ['create_task','update_task','delete_task','approve_leave_request','reject_leave_request'];
  const needsConfirm = isAudio || (isButtonReply && rawMsg !== 'yes_confirm');
  if (needsConfirm && toolCalls.some(function(t){ return WRITE_TOOLS.includes(t.function.name); })) {
    const tc   = toolCalls.find(function(t){ return WRITE_TOOLS.includes(t.function.name); });
    const args = JSON.parse(tc.function.arguments || '{}');
    let details = '';
    if (tc.function.name === 'create_task') {
      details = '• Title: *' + (args.title || '?') + '*' +
                '\n• Assignee: *' + (args.assignee_name || ctx.user_name) + '*' +
                (args.deadline ? '\n• Deadline: *' + args.deadline + '*' : '') +
                '\n• Priority: *' + (args.priority || 'medium') + '*';
    } else if (tc.function.name === 'update_task') {
      const ch = [];
      if (args.title)     ch.push('Title → ' + args.title);
      if (args.assignee_name) ch.push('Assignee → ' + args.assignee_name);
      if (args.deadline)      ch.push('Deadline → ' + args.deadline);
      if (args.priority)      ch.push('Priority → ' + args.priority);
      if (args.status)        ch.push('Status → ' + args.status);
      details = 'Task: *' + (args.task_title || args.task_id || 'task') + '*' +
                (ch.length > 0 ? '\n' + ch.map(function(c){ return '• ' + c; }).join('\n') : '');
    } else if (tc.function.name === 'delete_task') {
      details = 'DELETE task: *' + (args.task_title || args.task_id || '?') + '*\n⚠️ This cannot be undone.';
    } else if (tc.function.name === 'approve_leave_request') {
      details = 'APPROVE the leave request.';
    } else if (tc.function.name === 'reject_leave_request') {
      details = 'REJECT the leave request.';
    } else {
      details = tc.function.name;
    }
    return [{ json: {
      output: 'Please confirm:\n\n' + details + '\n\nConfirm?',
      confirmButtons: [
        { id: 'yes_confirm', title: 'Yes, do it' },
        { id: 'no_cancel',   title: 'No, cancel'  }
      ]
    }}];
  }
  // ── End interceptor ─────────────────────────────────────────────────────────

  messages.push(choice.message);
  for (const tc of toolCalls) {
    let toolResult;
    try { toolResult = await runTool(tc.function.name, JSON.parse(tc.function.arguments || '{}')); }
    catch(e) { toolResult = { error: e.message }; }
    messages.push({ role: 'tool', tool_call_id: tc.id, content: JSON.stringify(toolResult) });
  }
  resp   = await llmCall(messages);
  choice = resp.choices[0];
  iters++;
}

// Strip leaked tool-call JSON or trailing "Here's the task creation JSON:" blurbs
let output = (choice.message.content || '').trim();

  // Strip code-block fences and try to recover a leaked tool call
  const fenceMatch = output.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fenceMatch) {
    const inner = fenceMatch[1].trim();
    if (inner.startsWith('{')) {
      try {
        const tc = JSON.parse(inner);
        const toolName = tc.name || (tc.function && tc.function.name);
        const rawArgs  = tc.parameters || tc.arguments || {};
        const toolArgs = typeof rawArgs === 'string' ? JSON.parse(rawArgs) : rawArgs;
        if (toolName && tools.some(function(t){ return t.function.name === toolName; }) && iters < 5) {
          const toolRes = await runTool(toolName, toolArgs);
          const callId  = 'recovered_' + Date.now();
          messages.push({ role: 'assistant', content: null,
            tool_calls: [{ id: callId, type: 'function',
              function: { name: toolName, arguments: JSON.stringify(toolArgs) } }] });
          messages.push({ role: 'tool', tool_call_id: callId, content: JSON.stringify(toolRes) });
          const finalResp = await llmCall(messages, 'none');
          output = (finalResp.choices[0].message.content || '').trim();
        } else {
          output = '';
        }
      } catch(e2) { output = ''; }
    } else {
      output = inner;
    }
  }

  // Also recover bare JSON tool call (no code fence)
  if (!fenceMatch && /^\s*\{/.test(output)) {
    try {
      const tc = JSON.parse(output);
      const toolName = tc.name || (tc.function && tc.function.name);
      const rawArgs  = tc.parameters || tc.arguments || {};
      const toolArgs = typeof rawArgs === 'string' ? JSON.parse(rawArgs) : rawArgs;
      if (toolName && tools.some(function(t){ return t.function.name === toolName; }) && iters < 5) {
        const toolRes = await runTool(toolName, toolArgs);
        const callId  = 'recovered_' + Date.now();
        messages.push({ role: 'assistant', content: null,
          tool_calls: [{ id: callId, type: 'function',
            function: { name: toolName, arguments: JSON.stringify(toolArgs) } }] });
        messages.push({ role: 'tool', tool_call_id: callId, content: JSON.stringify(toolRes) });
        const finalResp = await llmCall(messages, 'none');
        output = (finalResp.choices[0].message.content || '').trim();
      } else {
        output = '';
      }
    } catch(e2) {}
  }

  // Strip any remaining bare JSON artifacts at end of output
  output = output.replace(/\{[\s\S]*?"name"[\s\S]*?"parameters"[\s\S]*?\}\s*$/, '').trim();
  output = output.replace(/here'?s the .*?json:?\s*$/i, '').trim();
  // Attach interactive confirm buttons when replying to audio CRUD confirmation
  let extras = {};
  if ((isAudio || isButtonReply) && /Confirm\?/i.test(output)) {
    extras.confirmButtons = [
      { id: 'yes_confirm', title: 'Yes, do it' },
      { id: 'no_cancel',   title: 'No, cancel'  }
    ];
  }
  return [{ json: { output, ...extras } }];

const isGreeting = $('Build Context').item.json.is_greeting;
const aiOutput = $('AI Agent').item.json.output;

if (!isGreeting) {
  return [{ json: { output: aiOutput, confirmButtons: $('AI Agent').item.json.confirmButtons ?? null, listItems: $('AI Agent').item.json.listItems ?? null, listButtonLabel: $('AI Agent').item.json.listButtonLabel ?? null } }];
}

// Extract the pre-written greeting from the system prompt
const sp = $('Build Context').item.json.system_prompt;
const marker = 'Do NOT call any tools. Do NOT add anything:\n\n';
const idx = sp.indexOf(marker);
const greetText = idx >= 0
  ? sp.substring(idx + marker.length)
  : `Hello ${$('Build Context').item.json.user_name}! I am *HRBot*, your AI HR assistant.

*Here is what I can help you with:*
- *Tasks* - list, create, or update tasks
- *Attendance* - check in/out, view history
- *Leaves* - check balance, apply for leave
- *Daily briefing* - today's summary
- *Team attendance* - admin only

What would you like to do?`;

return [{ json: { output: greetText, confirmButtons: null, listItems: null, listButtonLabel: null } }];
